import { IAuthenticator } from '../authentication/authenticator';
import { IRootProps } from '../types/IRootProps';
import { IRouter } from './router';
import { ISingleSpa } from './single-spa';
import { IAppSettings } from '../configuration/appsettings';
import { IUser, IFeatureToggle } from '../types/IRootProps';
import { StartupDependencies } from './startup-dependencies';
import { logError, logInfo } from '../../logger';

export class Startup {
  private readonly _authenticator: IAuthenticator;
  private readonly _user: IUser;
  private readonly _router: IRouter;
  private readonly _singleSpa: ISingleSpa;
  private readonly _appSettings: IAppSettings;
  private readonly _featureToggle: IFeatureToggle;

  constructor(deps: StartupDependencies) {
    this._authenticator = deps.authenticator;
    this._user = deps.user;
    this._router = deps.router;
    this._singleSpa = deps.singleSpa;
    this._appSettings = deps.appSettings;
    this._featureToggle = deps.featureToggle;
  }

  async run(): Promise<boolean> {
    // When OIDC is disabled the microfrontend manages its own auth (JWT).
    // Skip every network round-trip and start single-spa immediately.
    if (!this._appSettings.OIDC_ENABLED) {
      logInfo('[Startup] OIDC disabled — starting single-spa immediately');
      this._loadPage();
      return false;
    }

    try {
      let oidcUser = await this._authenticator.getUser();

      if (!oidcUser || oidcUser.expired) {
        logInfo('[Startup] No valid OIDC session — attempting silent sign-in');
        try {
          oidcUser = await this._authenticator.loginSilentAsync();
          logInfo('[Startup] Silent sign-in succeeded');
        } catch (silentError) {
          logInfo(`[Startup] Silent sign-in failed (${silentError}) — starting unauthenticated`);
          this._loadPage();
          return false;
        }
      }

      logInfo('[Startup] OIDC user authenticated — starting app');
      this._loadPage();
      return true;
    } catch (error) {
      logError(`[Startup] Unexpected error: ${error}`);
      this._loadPage();
      return false;
    }
  }

  private _loadPage = (): void => {
    const props: IRootProps = {
      name: undefined,
      user: this._user,
      authentication: this._authenticator,
      featureToggle: this._featureToggle,
    };
    this._singleSpa.start(props);
  };
}
