import { IFeatureToggle } from '../types/IRootProps';
import { AppSettings } from '../configuration/appsettings';
import { logError, logWarn } from '../../logger';

export class FeatureToggle implements IFeatureToggle {
  async getAllFeatureToggles(): Promise<Record<string, boolean>> {
    try {
      const response = await fetch(`${AppSettings.FEATURE_TOGGLE_API_URL}/feature-toggles`, {
        headers: { 'Content-Type': 'application/json' },
      });
      if (response.ok) {
        const data = await response.json();
        return (data.items as Record<string, boolean>) ?? (data as Record<string, boolean>);
      }
      logWarn(`[FeatureToggle] Non-OK response: ${response.status}`);
      return {};
    } catch (error) {
      logError(`[FeatureToggle] Failed to fetch: ${error}`);
      return {};
    }
  }
}
