const LOGOUT_CHANNEL = 'app-logout-channel';
const LOGOUT_MESSAGE = 'LOGOUT';
const LOGOUT_STORAGE_KEY = 'app-logout-signal';

export const initializeCrossTabLogout = (): void => {
  try {
    const channel = new BroadcastChannel(LOGOUT_CHANNEL);
    channel.onmessage = (event: MessageEvent) => {
      if (event.data === LOGOUT_MESSAGE) window.location.href = '/logout';
    };
  } catch {
    window.addEventListener('storage', (event: StorageEvent) => {
      if (event.key === LOGOUT_STORAGE_KEY && event.newValue === LOGOUT_MESSAGE) {
        localStorage.removeItem(LOGOUT_STORAGE_KEY);
        window.location.href = '/logout';
      }
    });
  }
};

export const broadcastLogoutToOtherTabs = (): void => {
  try {
    const channel = new BroadcastChannel(LOGOUT_CHANNEL);
    channel.postMessage(LOGOUT_MESSAGE);
    channel.close();
  } catch {
    localStorage.setItem(LOGOUT_STORAGE_KEY, LOGOUT_MESSAGE);
    setTimeout(() => localStorage.removeItem(LOGOUT_STORAGE_KEY), 200);
  }
};
