import { User, UserManager, UserManagerSettings } from 'oidc-client-ts';
import { IUserAuthentication, IUserProfile } from '../types/IRootProps';
import { UserProfile } from './user';
import { navigateToUrl } from 'single-spa';
import { logError, logInfo } from '../../logger';

export interface IAuthenticator extends IUserAuthentication {
  getUser(): Promise<User | null>;
  loginSilentAsync(): Promise<User>;
  handleLoginCallbackAsync(): Promise<IUserProfile>;
  handleSilentRenewCallbackAsync(): Promise<void>;
  getUserManager(): UserManager;
}

export class Authenticator implements IAuthenticator {
  private static instance: Authenticator;
  private readonly manager: UserManager;

  private constructor(manager: UserManager) {
    this.manager = manager;
  }

  static getInstance = (settings: UserManagerSettings): Authenticator => {
    if (!Authenticator.instance) {
      logInfo(`[OIDC] Creating UserManager — authority: ${settings.authority}`);
      const userManager = new UserManager(settings);

      userManager.events.addAccessTokenExpiring(() => { logInfo('[OIDC Events] Access token expiring soon'); });
      userManager.events.addAccessTokenExpired(() => { logInfo('[OIDC Events] Access token expired'); });
      userManager.events.addSilentRenewError((error: unknown) => {
        const msg = error instanceof Error ? error.message : JSON.stringify(error);
        logError(`[OIDC Events] Silent renew error: ${msg}`);
      });
      userManager.events.addUserSignedOut(() => { logInfo('[OIDC Events] User signed out externally'); });
      userManager.events.addUserSessionChanged(() => { logInfo('[OIDC Events] User session changed'); });

      Authenticator.instance = new Authenticator(userManager);
    }
    return Authenticator.instance;
  };

  getUserManager = (): UserManager => this.manager;

  getUser = async (): Promise<User | null> => this.manager.getUser();

  loginAsync = async (): Promise<void> => {
    logInfo('[OIDC] Starting sign-in redirect');
    await this.manager.signinRedirect({ state: window.location.pathname + window.location.search });
  };

  logoutAsync = async (): Promise<void> => {
    logInfo('[OIDC] Starting sign-out redirect');
    await this.manager.signoutRedirect();
  };

  loginSilentAsync = async (): Promise<User> => {
    logInfo('[OIDC] Attempting silent sign-in');
    const user = await this.manager.signinSilent();
    if (!user) throw new Error('[OIDC] Silent sign-in returned null');
    return user;
  };

  handleLoginCallbackAsync = async (): Promise<IUserProfile> => {
    logInfo('[OIDC] Processing login callback');
    const oidcUser = await this.manager.signinRedirectCallback();
    const profile = new UserProfile(oidcUser.profile as Record<string, unknown>);
    const returnPath = typeof oidcUser.state === 'string' ? oidcUser.state : '/';
    logInfo(`[OIDC] Login complete — redirecting to: ${returnPath}`);
    navigateToUrl(returnPath);
    return profile;
  };

  handleSilentRenewCallbackAsync = async (): Promise<void> => {
    logInfo('[OIDC] Processing silent renew callback');
    await this.manager.signinSilentCallback();
  };
}
