import { IUser, IUserProfile } from '../types/IRootProps';
import { IAuthenticator } from './authenticator';

export class UserProfile implements IUserProfile {
  userId: string;
  username: string;
  email: string;
  roles: string[];
  companyId?: string;
  companyName?: string;

  constructor(claims: Record<string, unknown>) {
    this.userId = String(claims['sub'] ?? '');
    this.username = String(claims['preferred_username'] ?? claims['email'] ?? '');
    this.email = String(claims['email'] ?? '');
    this.roles = Array.isArray(claims['roles'])
      ? (claims['roles'] as string[])
      : [claims['roles']].filter(Boolean) as string[];
    this.companyId = claims['company_id'] as string | undefined;
    this.companyName = claims['company_name'] as string | undefined;
  }
}

export class User implements IUser {
  private readonly _authenticator: IAuthenticator;

  constructor(authenticator: IAuthenticator) {
    this._authenticator = authenticator;
  }

  getUserProfile = async (): Promise<IUserProfile> => {
    const oidcUser = await this._authenticator.getUser();
    if (!oidcUser?.profile) {
      throw new Error('[User] No authenticated user');
    }
    return new UserProfile(oidcUser.profile as Record<string, unknown>);
  };

  getAccessToken = async (): Promise<string> => {
    const oidcUser = await this._authenticator.getUser();
    return oidcUser?.access_token ?? '';
  };
}
