import { IAppSettings } from '../configuration/appsettings';
import { logWarn } from '../../logger';

export interface IRouter {
  canVisit(pathname?: string): boolean;
}

export default class Router implements IRouter {
  private readonly _routes: string[] | null;

  constructor(appSettings: IAppSettings) {
    const raw = appSettings.ALLOWED_ROUTES;
    if (!raw) {
      this._routes = null;
      return;
    }
    try {
      this._routes = JSON.parse(raw);
    } catch {
      logWarn('[Router] ALLOWED_ROUTES is not valid JSON — allowing all routes');
      this._routes = null;
    }
  }

  canVisit = (pathname?: string): boolean => {
    if (!this._routes) return true;
    const path = pathname ?? window.location.pathname;
    if (this._routes.includes('/') && path === '/') return true;
    const [, firstSegment] = path.split('/');
    return this._routes.includes(firstSegment);
  };
}
