export interface IAppSettings {
  OIDC_ENABLED: boolean;
  AUTHORITY: string;
  CLIENT_ID: string;
  REDIRECT_URI: string;
  SILENT_RENEW_URI: string;
  POST_LOGOUT_URI: string;
  FEATURE_TOGGLE_API_URL: string;
  ALLOWED_ROUTES?: string;
}

export const AppSettings: IAppSettings = {
  OIDC_ENABLED: process.env.OIDC_ENABLED === 'true',
  AUTHORITY: process.env.AUTHORITY ?? '',
  CLIENT_ID: process.env.CLIENT_ID ?? '',
  REDIRECT_URI: process.env.REDIRECT_URI ?? `${window.location.origin}/oidc-callback`,
  SILENT_RENEW_URI: process.env.SILENT_RENEW_URI ?? `${window.location.origin}/oidc-silent-renew`,
  POST_LOGOUT_URI: process.env.POST_LOGOUT_URI ?? window.location.origin,
  FEATURE_TOGGLE_API_URL: process.env.FEATURE_TOGGLE_API_URL ?? '',
  ALLOWED_ROUTES: process.env.ALLOWED_ROUTES,
};
