import { IRootProps } from '../types/IRootProps';
import {
  constructApplications,
  constructLayoutEngine,
  constructRoutes,
} from 'single-spa-layout';

declare const System: { import: (name: string) => Promise<any> };

type HTMLLayoutData = {
  props: Record<string, any>;
  loaders: Record<string, unknown>;
};

import microfrontendLayout from '../../microfrontend-layout.html';
import { addErrorHandler, navigateToUrl, registerApplication, start } from 'single-spa';
import { logError, logInfo, logWarn } from '../../logger';

// No-op lifecycle returned when an app fails to load after all retries.
// Prevents single-spa from entering LOAD_ERROR state and showing error UI.
const noopLifecycle = {
  bootstrap: () => Promise.resolve(),
  mount:     () => Promise.resolve(),
  unmount:   () => Promise.resolve(),
};

export interface ISingleSpa {
  start(props: IRootProps): void;
  navigateTo(path: string): void;
}

export class SingleSpa implements ISingleSpa {
  private readonly MAX_RETRIES = 3;
  private readonly RETRY_DELAY = 1000;

  private async loadAppWithRetry(name: string, retryCount = 0): Promise<unknown> {
    try {
      logInfo(`[SingleSpa] Loading module: ${name}`);
      return await System.import(name);
    } catch (error) {
      logError(`[SingleSpa] Failed to load ${name} (attempt ${retryCount + 1}): ${error}`);
      if (retryCount < this.MAX_RETRIES) {
        const delay = this.RETRY_DELAY * Math.pow(2, retryCount);
        await new Promise((resolve) => setTimeout(resolve, delay));
        return this.loadAppWithRetry(name, retryCount + 1);
      }
      logWarn(`[SingleSpa] Gave up loading ${name} after ${this.MAX_RETRIES} retries — mounting no-op`);
      return noopLifecycle;
    }
  }

  // Programmatic navigation via single-spa — use instead of window.location for SPA transitions
  navigateTo(path: string): void {
    navigateToUrl(path);
  }

  private setupNavTransition(): void {
    let overlay = document.getElementById('spa-nav-overlay');
    if (!overlay) {
      overlay = document.createElement('div');
      overlay.id = 'spa-nav-overlay';
      document.body.appendChild(overlay);
    }

    // Show overlay just before apps switch — covers the unmount/mount gap
    window.addEventListener('single-spa:before-mount-routing-event', (evt: Event) => {
      const detail = (evt as CustomEvent).detail as { appsByNewStatus?: Record<string, string[]> };
      const { MOUNTED = [], NOT_MOUNTED = [] } = detail?.appsByNewStatus ?? {};
      // Only overlay when an actual app switch is happening
      if (MOUNTED.length > 0 || NOT_MOUNTED.length > 0) {
        document.getElementById('spa-nav-overlay')?.classList.add('visible');
      }
    });

    window.addEventListener('single-spa:routing-event', () => {
      document.getElementById('spa-nav-overlay')?.classList.remove('visible');
    });
  }

  private setupErrorHandler(): void {
    addErrorHandler((err) => {
      // Log only — never rethrow so single-spa doesn't surface error UI
      logError(`[SingleSpa] App lifecycle error [${(err as any).appOrParcelName ?? 'unknown'}]: ${err.message}`);
    });
  }

  start(props: IRootProps): void {
    document.querySelectorAll('.root-loader').forEach((el) => el.remove());

    this.setupErrorHandler();
    this.setupNavTransition();

    const layoutData: HTMLLayoutData = { props: props as Record<string, any>, loaders: {} };
    const routes = constructRoutes(microfrontendLayout, layoutData);
    const applications = constructApplications({
      routes,
      loadApp: ({ name }: { name: string }) => this.loadAppWithRetry(name) as any,
    });
    const layoutEngine = constructLayoutEngine({ routes, applications });

    applications.forEach(registerApplication);
    layoutEngine.activate();
    start({ urlRerouteOnly: true });
  }
}
