import { IAppSettings } from '../configuration/appsettings';
import { FeatureToggle } from '../featureToggle/featureToggle';
import Router from './router';
import { SingleSpa } from './single-spa';
import { Startup } from './startup';
import { IAuthenticator } from '../authentication/authenticator';
import { User } from '../authentication/user';

export const bootstrap = async (
  authenticator: IAuthenticator,
  appSettings: IAppSettings
): Promise<void> => {
  const user = new User(authenticator);
  const router = new Router(appSettings);
  const featureToggle = new FeatureToggle();

  const startup = new Startup({
    authenticator,
    user,
    router,
    singleSpa: new SingleSpa(),
    appSettings,
    featureToggle,
  });

  // Web.Home manages its own JWT auth — just start single-spa
  await startup.run();
};
