const fmt = (level: string, message: string | unknown): string =>
  `[${level}] ${new Date().toISOString()} ${message}`;

export const logInfo  = (message: string):          void => console.info( fmt('INFO',  message));
export const logError = (message: string | unknown): void => console.error(fmt('ERROR', message));
export const logWarn  = (message: string):           void => console.warn( fmt('WARN',  message));
